1	import {
2	  app,
3	  BrowserWindow,
4	  ipcMain,
5	  Menu,
6	  nativeTheme,
7	  session,
8	  shell,
9	} from "electron";
10	import contextMenu from "electron-context-menu";
11	import { IpcChannels, type SystemThemeVariant } from "../shared/ipc";
12	import { openAppOrigin } from "./app-url";
13	import { beginSignIn } from "./auth-flow";
14	import {
15	  getAuthSnapshot,
16	  getToken as getAuthToken,
17	  onAuthChanged,
18	  signOut as signOutAuth,
19	} from "./auth-store";
20	import { getBuildInfo } from "./build-info";
21	import { buildApplicationMenu } from "./menu";
22	import { getRuntimeConfig } from "./runtime-config";
23	import { getSentryInitOptions, initSentry } from "./sentry";
24	import {
25	  getSettings,
26	  onSettingsChanged,
27	  type SettingsSnapshot,
28	  updateSetting,
29	} from "./settings-store";
30	import {
31	  attachLocalShortcuts,
32	  registerGlobalShortcuts,
33	  unregisterGlobalShortcuts,
34	} from "./shortcuts";
35	import { createTray, destroyTray } from "./tray";
36	import { initUpdater, registerUpdaterIpc } from "./updater";
37	import { applyTitleBarOverlayTheme, createWindow } from "./windows/factory";
38	
39	declare const MAIN_WINDOW_VITE_DEV_SERVER_URL: string | undefined;
40	
41	const ALLOWED_EXTERNAL_PROTOCOLS = new Set(["http:", "https:", "mailto:"]);
42	
43	function currentThemeVariant(): SystemThemeVariant {
44	  return nativeTheme.shouldUseDarkColors ? "dark" : "light";
45	}
46	
47	function rendererDevServerOrigin(): string | null {
48	  return MAIN_WINDOW_VITE_DEV_SERVER_URL
49	    ? new URL(MAIN_WINDOW_VITE_DEV_SERVER_URL).origin
50	    : null;
51	}
52	
53	function openAllowedExternalUrl(url: string): void {
54	  try {
55	    const parsed = new URL(url);
56	    if (ALLOWED_EXTERNAL_PROTOCOLS.has(parsed.protocol)) {
57	      void shell.openExternal(url);
58	    }
59	  } catch {
60	    // ignore malformed urls
61	  }
62	}
63	
64	function buildContentSecurityPolicy(): string {
65	  const appOrigin = getRuntimeConfig().appOrigin;
66	
67	  const origin = rendererDevServerOrigin();
68	  if (origin) {
69	    const wsOrigin = origin.replace(/^http/, "ws");
70	    return [
71	      `default-src 'self' ${origin}`,
72	      `script-src 'self' 'unsafe-inline' ${origin}`,
73	      `style-src 'self' 'unsafe-inline' ${origin}`,
74	      `connect-src 'self' ${origin} ${wsOrigin} ${appOrigin}`,
75	      `img-src 'self' data: blob: ${origin}`,
76	      `font-src 'self' data: ${origin}`,
77	    ].join("; ");
78	  }
79	  return [
80	    "default-src 'self'",
81	    "script-src 'self'",
82	    "style-src 'self' 'unsafe-inline'",
83	    `connect-src 'self' ${appOrigin}`,
84	    "img-src 'self' data: blob:",
85	    "font-src 'self' data:",
86	  ].join("; ");
87	}
88	
89	function applyContentSecurityPolicy(): void {
90	  const csp = buildContentSecurityPolicy();
91	  session.defaultSession.webRequest.onHeadersReceived((details, callback) => {
92	    callback({
93	      responseHeaders: {
94	        ...details.responseHeaders,
95	        "Content-Security-Policy": [csp],
96	      },
97	    });
98	  });
99	}
100	
101	function hardenContents(contents: Electron.WebContents): void {
102	  contents.setWindowOpenHandler(({ url }) => {
103	    openAllowedExternalUrl(url);
104	    return { action: "deny" };
105	  });
106	
107	  contents.on("will-navigate", (event, url) => {
108	    const rendererOrigin = rendererDevServerOrigin();
109	    try {
110	      const target = new URL(url);
111	      if (rendererOrigin && target.origin === rendererOrigin) {
112	        return;
113	      }
114	      if (target.protocol === "file:") {
115	        return;
116	      }
117	      event.preventDefault();
118	      openAllowedExternalUrl(url);
119	    } catch {
120	      event.preventDefault();
121	    }
122	  });
123	}
124	
125	function registerIpcHandlers(): void {
126	  ipcMain.on(IpcChannels.getBuildInfoSync, (event) => {
127	    event.returnValue = getBuildInfo();
128	  });
129	
130	  ipcMain.on(IpcChannels.getSentryInitOptionsSync, (event) => {
131	    event.returnValue = getSentryInitOptions();
132	  });
133	
134	  ipcMain.on(IpcChannels.getSettingsSync, (event) => {
135	    event.returnValue = getSettings();
136	  });
137	
138	  ipcMain.on(IpcChannels.runtimeConfigSync, (event) => {
139	    event.returnValue = getRuntimeConfig();
140	  });
141	
142	  ipcMain.handle(IpcChannels.updateSetting, (_event, payload: unknown) => {
143	    if (!payload || typeof payload !== "object") {
144	      return getSettings();
145	    }
146	    const { key, value } = payload as {
147	      key: keyof SettingsSnapshot;
148	      value: SettingsSnapshot[keyof SettingsSnapshot];
149	    };
150	    if (!(key in getSettings())) {
151	      return getSettings();
152	    }
153	    return updateSetting(key, value);
154	  });
155	
156	  ipcMain.handle(
157	    IpcChannels.getSystemThemeVariant,
158	    (): SystemThemeVariant => currentThemeVariant()
159	  );
160	
161	  ipcMain.handle(IpcChannels.openApp, async () => {
162	    await openAppOrigin();
163	  });
164	
165	  ipcMain.on(IpcChannels.rendererError, (_event, payload: unknown) => {
166	    // eslint-disable-next-line no-console
167	    console.error("[renderer]", payload);
168	  });
169	
170	  ipcMain.handle(IpcChannels.openWindow, async (_event, kind: unknown) => {
171	    if (kind === "settings") {
172	      showSettingsWindow();
173	    } else if (kind === "hud") {
174	      await openHudWindow();
175	    } else if (kind === "primary") {
176	      await openPrimaryWindow();
177	    }
178	  });
179	
180	  ipcMain.on(IpcChannels.authSnapshotSync, (event) => {
181	    event.returnValue = getAuthSnapshot();
182	  });
183	  ipcMain.handle(IpcChannels.authGetToken, () => getAuthToken());
184	  ipcMain.handle(IpcChannels.authSignIn, () => beginSignIn());
185	  ipcMain.handle(IpcChannels.authSignOut, () => {
186	    signOutAuth();
187	  });
188	}
189	
190	function broadcastThemeUpdates(): void {
191	  nativeTheme.on("updated", () => {
192	    const variant = currentThemeVariant();
193	    for (const win of BrowserWindow.getAllWindows()) {
194	      win.webContents.send(IpcChannels.systemThemeVariantUpdated, variant);
195	      applyTitleBarOverlayTheme(win);
196	    }
197	  });
198	}
199	
200	type Kind = "primary" | "settings" | "hud";
201	
202	const windowsByKind = new Map<Kind, Set<BrowserWindow>>();
203	
204	function registerWindow(kind: Kind, win: BrowserWindow): void {
205	  const set = windowsByKind.get(kind) ?? new Set<BrowserWindow>();
206	  set.add(win);
207	  windowsByKind.set(kind, set);
208	  win.once("closed", () => {
209	    set.delete(win);
210	  });
211	}
212	
213	async function openKind(kind: Kind): Promise<BrowserWindow> {
214	  const win = await createWindow({ kind, harden: hardenContents });
215	  registerWindow(kind, win);
216	  attachLocalShortcuts(win);
217	  if (!app.isPackaged) {
218	    win.webContents.openDevTools({ mode: "detach" });
219	  }
220	  return win;
221	}
222	
223	export function openPrimaryWindow(): Promise<BrowserWindow> {
224	  return openKind("primary");
225	}
226	
227	export function openSettingsWindow(): Promise<BrowserWindow> {
228	  return openKind("settings");
229	}
230	
231	export function openHudWindow(): Promise<BrowserWindow> {
232	  return openKind("hud");
233	}
234	
235	function showSettingsWindow(): void {
236	  const existing = findWindow("settings");
237	  if (existing) {
238	    existing.show();
239	    existing.focus();
240	    return;
241	  }
242	  void openSettingsWindow();
243	}
244	
245	function findWindow(kind: Kind): BrowserWindow | null {
246	  const set = windowsByKind.get(kind);
247	  if (!set) {
248	    return null;
249	  }
250	  for (const win of set) {
251	    if (!win.isDestroyed()) {
252	      return win;
253	    }
254	  }
255	  return null;
256	}
257	
258	function toggleHudWindow(): void {
259	  const existing = findWindow("hud");
260	  if (existing) {
261	    if (existing.isVisible()) {
262	      existing.hide();
263	    } else {
264	      existing.show();
265	      existing.focus();
266	    }
267	  } else {
268	    void openHudWindow();
269	  }
270	}
271	
272	const trayActions = {
273	  showPrimary: () => {
274	    const existing = findWindow("primary");
275	    if (existing) {
276	      existing.show();
277	      existing.focus();
278	    } else {
279	      void openPrimaryWindow();
280	    }
281	  },
282	  toggleHud: toggleHudWindow,
283	};
284	
285	function applySettings(snapshot: SettingsSnapshot): void {
286	  nativeTheme.themeSource = snapshot.themeSource;
287	  if (process.platform !== "linux" && app.isPackaged) {
288	    app.setLoginItemSettings({ openAtLogin: snapshot.launchAtLogin });
289	  }
290	  if (snapshot.showInMenuBar) {
291	    createTray(trayActions);
292	  } else {
293	    destroyTray();
294	  }
295	}
296	
297	function broadcastSettings(snapshot: SettingsSnapshot): void {
298	  for (const win of BrowserWindow.getAllWindows()) {
299	    win.webContents.send(IpcChannels.settingsChanged, snapshot);
300	  }
301	}
302	
303	initSentry();
304	
305	contextMenu({
306	  showInspectElement: !app.isPackaged,
307	  showSaveImageAs: true,
308	  showCopyImage: true,
309	  showSelectAll: true,
310	});
311	
312	app.whenReady().then(() => {
313	  applyContentSecurityPolicy();
314	  session.defaultSession.setPermissionRequestHandler(
315	    (_contents, _permission, callback) => {
316	      callback(false);
317	    }
318	  );
319	
320	  Menu.setApplicationMenu(
321	    buildApplicationMenu({
322	      openSettings: showSettingsWindow,
323	      openHud: () => {
324	        void openHudWindow();
325	      },
326	    })
327	  );
328	
329	  registerIpcHandlers();
330	  registerUpdaterIpc();
331	  broadcastThemeUpdates();
332	  registerGlobalShortcuts({ toggleHud: toggleHudWindow });
333	  applySettings(getSettings());
334	  if (getSettings().checkForUpdatesAutomatically) {
335	    initUpdater();
336	  }
337	  onSettingsChanged((snapshot) => {
338	    applySettings(snapshot);
339	    broadcastSettings(snapshot);
340	  });
341	  void openPrimaryWindow();
342	
343	  onAuthChanged((snapshot) => {
344	    for (const win of BrowserWindow.getAllWindows()) {
345	      win.webContents.send(IpcChannels.authChanged, snapshot);
346	    }
347	  });
348	
349	  app.on("activate", () => {
350	    if (BrowserWindow.getAllWindows().length === 0) {
351	      void openPrimaryWindow();
352	    }
353	  });
354	});
355	
356	app.on("will-quit", () => {
357	  unregisterGlobalShortcuts();
358	  destroyTray();
359	});
360	
361	app.on("web-contents-created", (_event, contents) => {
362	  hardenContents(contents);
363	});
364	
365	app.on("window-all-closed", () => {
366	  if (process.platform !== "darwin") {
367	    app.quit();
368	  }
369	});
370

